def log_audit(user_id, action, success=True, details=None):
    log = AuditLog(
        user_id=user_id,
        action=action,
        ip_address=request.remote_addr,
        user_agent=request.headers.get('User-Agent'),
        success=success,
        details=details
    )
    db.session.add(log)
    db.session.commit()

def send_email(to_email, subject, body):
    try:
        msg = MIMEMultipart()
        msg['From'] = FROM_EMAIL
        msg['To'] = to_email
        msg['Subject'] = subject
        msg.attach(MIMEText(body, 'html'))
        
        server = smtplib.SMTP(SMTP_SERVER, SMTP_PORT)
        server.starttls()
        server.login(SMTP_USERNAME, SMTP_PASSWORD)
        server.send_message(msg)
        server.quit()
        return True
    except Exception as e:
        print(f"Email error: {e}")
        return False

def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        session_token = request.headers.get('Authorization')
        if not session_token:
            return jsonify({'error': 'No session token provided'}), 401
        
        if session_token.startswith('Bearer '):
            session_token = session_token[7:]
        
        session = Session.query.filter_by(session_token=session_token).first()
        if not session or session.expires_at < datetime.utcnow():
            return jsonify({'error': 'Invalid or expired session'}), 401
        
        user = User.query.get(session.user_id)
        if not user:
            return jsonify({'error': 'User not found'}), 401
        
        if user.mfa_enabled and not session.mfa_verified:
            return jsonify({'error': 'MFA verification required'}), 403
        
        request.current_user = user
        request.current_session = session
        return f(*args, **kwargs)
    return decorated_function

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400
    
    if User.query.filter_by(email=email).first():
        return jsonify({'error': 'Email already registered'}), 400
    
    user = User(
        email=email,
        password_hash=generate_password_hash(password)
    )
    db.session.add(user)
    db.session.commit()
    
    log_audit(user.id, 'USER_REGISTERED')
    
    return jsonify({'message': 'User registered successfully', 'user_id': user.id}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400
    
    user = User.query.filter_by(email=email).first()
    if not user or not check_password_hash(user.password_hash, password):
        log_audit(None, 'LOGIN_FAILED', success=False, details=f'Email: {email}')
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session_token = secrets.token_urlsafe(32)
    session = Session(
        user_id=user.id,
        session_token=session_token,
        mfa_verified=not user.mfa_enabled,
        expires_at=datetime.utcnow() + timedelta(hours=24)
    )
    db.session.add(session)
    db.session.commit()
    
    log_audit(user.id, 'LOGIN_SUCCESS')
    
    response = {
        'session_token': session_token,
        'mfa_required': user.mfa_enabled
    }
    
    return jsonify(response), 200

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    data = request.get_json()
    session_token = data.get('session_token')
    mfa_code = data.get('mfa_code')
    
    if not session_token or not mfa_code:
        return jsonify({'error': 'Session token and MFA code required'}), 400
    
    session = Session.query.filter_by(session_token=session_token).first()
    if not session or session.expires_at < datetime.utcnow():
        return jsonify({'error': 'Invalid or expired session'}), 401
    
    user = User.query.get(session.user_id)
    if not user or not user.mfa_enabled:
        return jsonify({'error': 'MFA not enabled'}), 400
    
    totp = pyotp.TOTP(user.mfa_secret)
    if not totp.verify(mfa_code, valid_window=1):
        log_audit(user.id, 'MFA_VERIFICATION_FAILED', success=False)
        return jsonify({'error': 'Invalid MFA code'}), 401
    
    session.mfa_verified = True
    db.session.commit()
    
    log_audit(user.id, 'MFA_VERIFICATION_SUCCESS')
    
    return jsonify({'message': 'MFA verified successfully'}), 200

@app.route('/enable-mfa', methods=['POST'])
@require_auth
def enable_mfa():
    user = request.current_user
    
    if user.mfa_enabled:
        return jsonify({'error': 'MFA already enabled'}), 400
    
    secret = pyotp.random_base32()
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(user.email, issuer_name="MFA System")
    
    user.mfa_secret = secret
    db.session.commit()
    
    return jsonify({
        'message': 'MFA secret generated. Please verify to enable.',
        'secret': secret,
        'provisioning_uri': provisioning_uri
    }), 200

