@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email required'}), 400
    
    user = User.query.filter_by(email=email).first()
    
    if user:
        MFAResetToken.query.filter_by(user_id=user.id, used=False).filter(
            MFAResetToken.expires_at > datetime.utcnow()
        ).update({'used': True})
        db.session.commit()
        
        token = secrets.token_urlsafe(32)
        reset_token = MFAResetToken(
            user_id=user.id,
            token=token,
            expires_at=datetime.utcnow() + timedelta(hours=1),
            requires_password_verification=True
        )
        db.session.add(reset_token)
        db.session.commit()
        
        reset_link = f"{request.host_url}confirm-reset-mfa?token={token}"
        email_body = f"""
        <html>
        <body>
            <h2>MFA Reset Request</h2>
            <p>You have requested to reset your MFA settings.</p>
            <p>Click the link below to proceed with the reset:</p>
            <p><a href="{reset_link}">Reset MFA</a></p>
            <p>This link will expire in 1 hour.</p>
            <p><strong>Important:</strong> You will need to verify your password to complete the reset.</p>
            <p>If you did not request this reset, please ignore this email and contact support immediately.</p>
        </body>
        </html>
        """
        
        send_email(user.email, "MFA Reset Request", email_body)
        log_audit(user.id, 'MFA_RESET_REQUESTED')
    
    return jsonify({'message': 'If the email is registered, a reset link has been sent'}), 200

@app.route('/confirm-reset-mfa', methods=['GET', 'POST'])
def confirm_reset_mfa():
    if request.method == 'GET':
        token = request.args.get('token')
        if not token:
            return jsonify({'error': 'Token required'}), 400
        
        reset_token = MFAResetToken.query.filter_by(token=token, used=False).first()
        if not reset_token or reset_token.expires_at < datetime.utcnow():
            return jsonify({'error': 'Invalid or expired token'}), 400
        
        html = f"""
        <html>
        <body>
            <h2>Reset MFA</h2>
            <form method="POST" action="/confirm-reset-mfa">
                <input type="hidden" name="token" value="{token}">
                <label>Password:</label>
                <input type="password" name="password" required>
                <button type="submit">Reset MFA</button>
            </form>
        </body>
        </html>
        """
        return render_template_string(html)
    
    elif request.method == 'POST':
        token = request.form.get('token')
        password = request.form.get('password')
        
        if not token or not password:
            return jsonify({'error': 'Token and password required'}), 400
        
        reset_token = MFAResetToken.query.filter_by(token=token, used=False).first()
        if not reset_token or reset_token.expires_at < datetime.utcnow():
            return jsonify({'error': 'Invalid or expired token'}), 400
        
        user = User.query.get(reset_token.user_id)
        if not user:
            return jsonify({'error': 'User not found'}), 404
        
        if not check_password_hash(user.password_hash, password):
            log_audit(user.id, 'MFA_RESET_FAILED', success=False, details='Invalid password')
            return jsonify({'error': 'Invalid password'}), 401
        
        if user.mfa_enabled:
            user.mfa_enabled = False
            user.mfa_secret = None
            
            Session.query.filter_by(user_id=user.id).delete()
        
        reset_token.used = True
        db.session.commit()
        
        log_audit(user.id, 'MFA_RESET_COMPLETED')
        
        return jsonify({'message': 'MFA has been reset successfully. You can now log in with your password.'}), 200

@app.route('/user/profile', methods=['GET'])
@require_auth
def get_profile():
    user = request.current_user
    return jsonify({
        'email': user.email,
        'mfa_enabled': user.mfa_enabled,
        'created_at': user.created_at.isoformat()
    }), 200

@app.route('/audit-logs', methods=['GET'])
@require_auth
def get_audit_logs():
    user = request.current_user
    logs = AuditLog.query.filter_by(user_id=user.id).order_by(AuditLog.created_at.desc()).limit(50).all()
    
    return jsonify({
        'logs': [{
            'action': log.action,
            'success': log.success,
            'ip_address': log.ip_address,
            'created_at': log.created_at.isoformat(),
            'details': log.details
        } for log in logs]
    }), 200

